// embed-dictionary.mjs — embed an English word list via the LOCAL GPU /hidden-embed service.
// Sovereign: plain Node (no Python, no HF). Tokenizes with our qwen vocab (qwen3-8b-temp-vocab.json,
// greedy 'Ġ'-prefix longest-match) — the SAME tokenizer the R1 grind + dispatcher use, so the space
// stays consistent. Runs ON the gaming PC, hits 127.0.0.1:8093 DIRECTLY (no SkyMesh gateway / agent /
// per-word RTT — all of which clogged). Concurrent, resume-aware, checkpoints (survives a freeze).
//
//   node embed-dictionary.mjs --out gpu_ctxemb.json --workers 12
//   EDGEWORK_API_TOKEN=... node embed-dictionary.mjs --out gpu_ctxemb.json --workers 12 --upload
//
// GPU contract: POST /hidden-embed, body = raw LE u32 token ids, response = raw LE f32[896].
// --upload streams JSON shards + a manifest to world-knots R2 so the Mac collector auto-deploys v2.
//
// STREAMING persistence (handles the full ~370k dict): the local DB is NDJSON appended one word per
// line (never one giant JSON string — that hit V8's ~512MB max-string-length at ~76k words and broke
// saves+uploads). Only the current shard buffer + the done/uploaded key-sets live in memory; the R2
// shards are the source of truth and the manifest is continued across restarts so a rerun never
// clobbers prior shards. Resume skips words already uploaded (R2) or already in the local NDJSON.
import fs from 'fs';
import path from 'path';
import readline from 'readline';
import { fileURLToPath } from 'url';

const DWYL = 'https://raw.githubusercontent.com/dwyl/english-words/master/words_alpha.txt';
const here = path.dirname(fileURLToPath(import.meta.url));
const arg = (f, d) => (process.argv.includes(f) ? process.argv[process.argv.indexOf(f) + 1] : d);
const has = (f) => process.argv.includes(f);

const OUT = arg('--out', 'gpu_ctxemb.json');
const URL = arg('--url', 'http://127.0.0.1:8093/hidden-embed');
const WORKERS = Number(arg('--workers', '12'));
const DIM = Number(arg('--dim', '896'));
const CHECKPOINT = Number(arg('--checkpoint', '1000'));
const SHARD = Number(arg('--shard-words', '4000'));
const RUN = arg('--run-id', 'current');
const R2 = (arg('--r2-base', process.env.EDGEWORK_R2_PROXY || 'https://www-edgework-app.edgework.ai/api/v1/r2')).replace(/\/$/, '');
const UPLOAD = has('--upload');
const TOKEN = process.env.EDGEWORK_API_TOKEN;
// vocab: walk up to the repo's sovereign vocab cache (override with --vocab)
const VOCAB = arg('--vocab', path.resolve(here, '../../../../../apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json'));

if (UPLOAD && !TOKEN) { console.error('WARN: --upload set but EDGEWORK_API_TOKEN missing; upload disabled'); }
const doUpload = UPLOAD && !!TOKEN;

const vocab = JSON.parse(fs.readFileSync(VOCAB, 'utf8')).vocab;
const vset = new Set(Object.keys(vocab));
const tokenize = (t) => { const ids = []; for (const w of t.toLowerCase().split(/\s+/).filter(Boolean)) { let s = 'Ġ' + w; while (s.length) { let took = ''; for (let l = Math.min(s.length, 24); l >= 1; l--) { const c = s.slice(0, l); if (vset.has(c)) { took = c; break; } } if (!took) { s = s.slice(1); continue; } ids.push(vocab[took]); s = s.slice(took.length); } } return ids; };

async function loadWords() {
  const p = arg('--words');
  let txt;
  if (p && fs.existsSync(p)) txt = fs.readFileSync(p, 'utf8');
  else { console.error('fetching dwyl word list...'); txt = await (await fetch(DWYL)).text(); }
  const seen = new Set(), out = [];
  for (const w of txt.split(/\s+/)) { const x = w.trim().toLowerCase(); if (/^[a-z]{2,}$/.test(x) && !seen.has(x)) { seen.add(x); out.push(x); } }
  return out;
}

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const putR2 = async (key, body, ct) => {
  // The R2 proxy drops connections intermittently (ECONNRESET); without retry a
  // single blip silently drops a 4000-word shard (recover with recover-upload.mjs).
  // Retry network errors + 5xx/429 with exponential backoff.
  let lastErr;
  for (let attempt = 0; attempt < 7; attempt++) {
    try {
      const r = await fetch(`${R2}/world-knots/${key}`, { method: 'PUT', headers: { Authorization: `Bearer ${TOKEN}`, 'content-type': ct }, body });
      if (r.ok) return;
      if (r.status >= 500 || r.status === 429) lastErr = new Error('PUT ' + key + ' -> ' + r.status);
      else throw new Error('PUT ' + key + ' -> ' + r.status); // 4xx — don't retry
    } catch (e) { lastErr = e; }
    await sleep(Math.min(500 * 2 ** attempt, 8000));
  }
  throw lastErr;
};
const embed = async (word) => {
  const ids = tokenize(word); if (!ids.length) return null;
  const body = new Uint8Array(ids.length * 4); const dv = new DataView(body.buffer);
  ids.forEach((id, i) => dv.setUint32(i * 4, id >>> 0, true));
  const res = await fetch(URL, { method: 'POST', headers: { 'content-type': 'application/octet-stream' }, body });
  if (!res.ok) throw new Error('embed ' + res.status);
  const buf = Buffer.from(await res.arrayBuffer()); if (buf.length !== DIM * 4) throw new Error('bad dim ' + buf.length / 4);
  const d = new DataView(buf.buffer, buf.byteOffset, buf.byteLength); const v = new Array(DIM);
  for (let i = 0; i < DIM; i++) v[i] = Math.round(d.getFloat32(i * 4, true) * 1e5) / 1e5;
  return v;
};

// ── streaming persistence ───────────────────────────────────────────────────
const ndpath = (OUT.endsWith('.json') ? OUT.slice(0, -5) : OUT) + '.ndjson';
const upath = OUT + '.uploaded.json';
const uploaded = new Set(fs.existsSync(upath) ? JSON.parse(fs.readFileSync(upath, 'utf8')) : []);
// resume: words already embedded into the local NDJSON (stream the keys — never one giant string)
const done = new Set();
if (fs.existsSync(ndpath)) {
  const rl = readline.createInterface({ input: fs.createReadStream(ndpath), crlfDelay: Infinity });
  for await (const line of rl) { const t = line.indexOf('\t'); if (t > 0) done.add(line.slice(0, t)); }
  console.error(`resumed ${done.size} from ${ndpath}`);
}
const ndout = fs.createWriteStream(ndpath, { flags: 'a' });

// continue the shard sequence + manifest from R2 so a restart never clobbers prior shards
let manifestShards = [], shardSeq = 0;
if (doUpload) {
  try {
    const r = await fetch(`${R2}/world-knots/gpu-embed/${RUN}/manifest.json`, { headers: { Authorization: `Bearer ${TOKEN}` } });
    if (r.ok) { const m = await r.json(); manifestShards = Array.isArray(m.shards) ? m.shards : []; shardSeq = manifestShards.length; console.error(`continuing manifest: ${shardSeq} shards, ${m.words} words`); }
  } catch { /* fresh run */ }
}

let pending = [];          // [{w,v}] embedded but not yet uploaded in a shard
let flushing = false;      // single-flight guard so concurrent workers don't double-upload
async function flushShards(final = false) {
  if (!doUpload) { if (final) pending = []; return; }
  if (flushing) return; flushing = true;
  try {
    while (pending.length >= SHARD || (final && pending.length)) {
      const chunk = pending.slice(0, SHARD); pending = pending.slice(chunk.length);
      const key = `gpu-embed/${RUN}/shard-${String(++shardSeq).padStart(4, '0')}.json`;
      const obj = {}; for (const e of chunk) obj[e.w] = e.v;   // shard ~28MB — safely under the string limit
      await putR2(key, JSON.stringify(obj), 'application/json');
      manifestShards.push(key); chunk.forEach((e) => uploaded.add(e.w));
      fs.writeFileSync(upath, JSON.stringify([...uploaded]));
      await putR2(`gpu-embed/${RUN}/manifest.json`, JSON.stringify({ shards: manifestShards, words: uploaded.size, dim: DIM, updated: Date.now() }), 'application/json');
      console.error(`  uploaded ${key} (${chunk.length}) · ${uploaded.size} total`);
    }
  } catch (e) { console.error('  upload fail:', e.message); }
  finally { flushing = false; }
}

const words = await loadWords();
const todo = words.filter((w) => !done.has(w) && !uploaded.has(w));
console.error(`${words.length} words | ${uploaded.size} uploaded | ${done.size} local | ${todo.length} to embed | ${WORKERS} workers | upload=${doUpload}`);
let i = 0, embedded = 0, fail = 0; const t0 = Date.now();
async function worker() {
  while (i < todo.length) {
    const w = todo[i++];
    try {
      const v = await embed(w);
      if (!v) continue;
      ndout.write(w + '\t' + JSON.stringify(v) + '\n');
      done.add(w); embedded++;
      if (!uploaded.has(w)) pending.push({ w, v });
      if (pending.length >= SHARD) await flushShards();
      if (embedded % CHECKPOINT === 0) console.error(`  ${embedded} this-run (${uploaded.size} up) · ${fail} fail · ${(embedded / ((Date.now() - t0) / 1000)).toFixed(1)}/s`);
    } catch (e) { fail++; if (fail <= 10) console.error('  fail', w, e.message); }
  }
}
await Promise.all(Array.from({ length: WORKERS }, worker));
await new Promise((r) => ndout.end(r));
// final drain (loop guards against the single-flight skip leaving a tail)
let guard = 0;
while (pending.length && guard++ < 1000) { const n = pending.length; await flushShards(true); if (pending.length === n) break; }
console.error(`DONE ${embedded} embedded this run · ${uploaded.size} uploaded total · ${fail} fail · ${ndpath}`);
